{
  "name": "site",
  "type": "module",
  "version": "0.0.1",
  "packageManager": "pnpm@10.33.2",
  "engines": {
    "node": ">=22.12.0"
  },
  "scripts": {
    "dev": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro dev",
    "build": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro build",
    "preview": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro preview",
    "check": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro check",
    "lint": "eslint src/scripts/**/*.ts",
    "astro": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro"
  },
  "dependencies": {
    "@astrojs/vercel": "^10.0.8",
    "astro": "^6.4.4"
  },
  "devDependencies": {
    "@astrojs/check": "^0.9.9",
    "cross-env": "10.1.0",
    "eslint": "^10.4.1",
    "typescript": "^6.0.3",
    "typescript-eslint": "^8.61.0"
  }
}

---
import PageLayout from '../layouts/PageLayout.astro';
---

<PageLayout name="tropical geometry calculator" back wide>
  <p class="tropical-intro">Work in min-plus tropical arithmetic: <code>a ŌŖĢ b = min(a,b)</code> and <code>a ŌŖŚ b = a + b</code>. Tropical polynomials become lower envelopes of lines.</p>

  <section class="tropical-panel" id="tropical-app">
    <div class="tropical-grid">
      <form class="tropical-card" id="tropical-arithmetic-form">
        <h2>arithmetic</h2>
        <label>
          a
          <input id="tropical-a" type="number" step="any" value="2" />
        </label>
        <label>
          b
          <input id="tropical-b" type="number" step="any" value="5" />
        </label>
        <button class="toolbar-button" type="submit">compute</button>
        <div class="tropical-output" id="tropical-arithmetic-output" aria-live="polite"></div>
      </form>

      <form class="tropical-card" id="tropical-poly-form">
        <h2>polynomial</h2>
        <p class="tropical-note">Coefficients low to high. Example <code>0,3,1</code> means <code>0 ŌŖĢ 3x ŌŖĢ 1x┬▓</code>.</p>
        <label>
          coefficients
          <input id="tropical-coefficients" type="text" value="0,3,1" />
        </label>
        <label>
          x
          <input id="tropical-x" type="number" step="any" value="2" />
        </label>
        <button class="toolbar-button" type="submit">evaluate</button>
        <div class="tropical-output" id="tropical-poly-output" aria-live="polite"></div>
      </form>

      <article class="tropical-card tropical-wide">
        <h2>curve</h2>
        <div class="tropical-controls">
          <label>
            x min
            <input id="tropical-x-min" type="number" step="any" value="-6" />
          </label>
          <label>
            x max
            <input id="tropical-x-max" type="number" step="any" value="6" />
          </label>
        </div>
        <div class="tropical-svg-wrap">
          <svg id="tropical-plot" role="img" aria-label="Tropical polynomial plot"></svg>
        </div>
        <div class="tropical-output" id="tropical-roots-output" aria-live="polite"></div>
      </article>
    </div>
  </section>
</PageLayout>

<style>
  .tropical-intro,
  .tropical-note,
  .tropical-muted {
    color: var(--muted);
  }

  .tropical-panel {
    display: grid;
    gap: 1rem;
  }

  .tropical-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(min(100%, 22rem), 1fr));
    gap: 1rem;
  }

  .tropical-wide {
    grid-column: 1 / -1;
  }

  .tropical-card {
    border: 1px solid var(--line);
    padding: 1rem;
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
  }

  .tropical-card h2 {
    font-size: 1rem;
    margin-bottom: 0.25rem;
  }

  .tropical-card label {
    display: grid;
    gap: 0.25rem;
    color: var(--muted);
  }

  .tropical-card input {
    width: 100%;
    background: transparent;
    color: var(--fg);
    border: 1px solid var(--line);
    border-radius: 4px;
    padding: 0.35rem 0.45rem;
    font: inherit;
  }

  .tropical-controls {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(8rem, 1fr));
    gap: 0.75rem;
  }

  .tropical-output {
    border-top: 1px solid var(--line);
    padding-top: 0.75rem;
    overflow-x: auto;
  }

  .tropical-svg-wrap {
    width: 100%;
    overflow: auto;
    border: 1px solid var(--line);
  }

  #tropical-plot {
    display: block;
    width: 100%;
    min-width: 38rem;
    height: 24rem;
    background: color-mix(in srgb, var(--bg) 94%, var(--fg));
  }

  .tropical-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.85rem;
  }

  .tropical-table th,
  .tropical-table td {
    border-bottom: 1px solid var(--line);
    padding: 0.25rem 0.4rem;
    text-align: left;
    white-space: nowrap;
  }
</style>

<script>
  import '../scripts/tropical.ts';
</script>

export {};

const arithmeticForm = document.querySelector<HTMLFormElement>("#tropical-arithmetic-form");
const aInput = document.querySelector<HTMLInputElement>("#tropical-a");
const bInput = document.querySelector<HTMLInputElement>("#tropical-b");
const arithmeticOutput = document.querySelector<HTMLDivElement>("#tropical-arithmetic-output");

const polyForm = document.querySelector<HTMLFormElement>("#tropical-poly-form");
const coefficientsInput = document.querySelector<HTMLInputElement>("#tropical-coefficients");
const xInput = document.querySelector<HTMLInputElement>("#tropical-x");
const xMinInput = document.querySelector<HTMLInputElement>("#tropical-x-min");
const xMaxInput = document.querySelector<HTMLInputElement>("#tropical-x-max");
const polyOutput = document.querySelector<HTMLDivElement>("#tropical-poly-output");
const rootsOutput = document.querySelector<HTMLDivElement>("#tropical-roots-output");
const plot = document.querySelector<SVGSVGElement>("#tropical-plot");

interface TermValue {
  degree: number;
  coefficient: number;
  value: number;
}

interface Root {
  x: number;
  terms: number[];
}

function escapeHtml(text: string): string {
  return text.replace(/[&<>"]/g, (ch) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", "\"": "&quot;" })[ch]!);
}

function readNumber(input: HTMLInputElement, name: string): number {
  const value = Number(input.value);
  if (!Number.isFinite(value)) throw new Error(`${name} must be a finite number`);
  return value;
}

function parseCoefficients(text: string): number[] {
  const coefficients = text.split(",").map((part) => part.trim()).map((part) => part === "Ōł×" || part.toLowerCase() === "inf" ? Number.POSITIVE_INFINITY : Number(part));
  if (coefficients.length === 0 || coefficients.some((value) => Number.isNaN(value))) {
    throw new Error("enter comma-separated numbers, using Ōł× or inf to omit a term");
  }
  if (coefficients.every((value) => !Number.isFinite(value))) throw new Error("at least one coefficient must be finite");
  return coefficients;
}

function termsAt(coefficients: number[], x: number): TermValue[] {
  return coefficients
    .map((coefficient, degree) => ({ degree, coefficient, value: coefficient + degree * x }))
    .filter((term) => Number.isFinite(term.coefficient));
}

function evaluate(coefficients: number[], x: number): { value: number; winners: TermValue[]; terms: TermValue[] } {
  const terms = termsAt(coefficients, x);
  const value = Math.min(...terms.map((term) => term.value));
  const winners = terms.filter((term) => Math.abs(term.value - value) < 1e-9);
  return { value, winners, terms };
}

function formatNumber(value: number): string {
  if (!Number.isFinite(value)) return "Ōł×";
  return Math.abs(value - Math.round(value)) < 1e-9 ? String(Math.round(value)) : value.toFixed(4).replace(/0+$/, "").replace(/\.$/, "");
}

function monomial(term: TermValue): string {
  const coefficient = formatNumber(term.coefficient);
  if (term.degree === 0) return coefficient;
  return `${coefficient}x${term.degree === 1 ? "" : `<sup>${term.degree}</sup>`}`;
}

function roots(coefficients: number[]): Root[] {
  const candidates = new Map<string, Root>();
  const finite = coefficients.map((coefficient, degree) => ({ coefficient, degree })).filter((term) => Number.isFinite(term.coefficient));

  finite.forEach((a, i) => {
    finite.slice(i + 1).forEach((b) => {
      if (a.degree === b.degree) return;
      const x = (b.coefficient - a.coefficient) / (a.degree - b.degree);
      const result = evaluate(coefficients, x);
      if (result.winners.length >= 2) {
        candidates.set(formatNumber(x), { x, terms: result.winners.map((term) => term.degree) });
      }
    });
  });

  return [...candidates.values()].sort((a, b) => a.x - b.x);
}

function renderArithmetic() {
  if (!aInput || !bInput || !arithmeticOutput) return;
  try {
    const a = readNumber(aInput, "a");
    const b = readNumber(bInput, "b");
    arithmeticOutput.innerHTML = `
      <table class="tropical-table">
        <tr><th>operation</th><th>ordinary</th><th>tropical</th></tr>
        <tr><td>addition</td><td>${formatNumber(a)} + ${formatNumber(b)} = ${formatNumber(a + b)}</td><td>${formatNumber(a)} ŌŖĢ ${formatNumber(b)} = min(...) = <strong>${formatNumber(Math.min(a, b))}</strong></td></tr>
        <tr><td>multiplication</td><td>${formatNumber(a)} ├Ś ${formatNumber(b)} = ${formatNumber(a * b)}</td><td>${formatNumber(a)} ŌŖŚ ${formatNumber(b)} = ${formatNumber(a)} + ${formatNumber(b)} = <strong>${formatNumber(a + b)}</strong></td></tr>
      </table>
    `;
  } catch (error) {
    arithmeticOutput.innerHTML = `<p>${escapeHtml(error instanceof Error ? error.message : String(error))}</p>`;
  }
}

function renderPolynomial() {
  if (!coefficientsInput || !xInput || !xMinInput || !xMaxInput || !polyOutput || !rootsOutput) return;
  try {
    const coefficients = parseCoefficients(coefficientsInput.value);
    const x = readNumber(xInput, "x");
    const result = evaluate(coefficients, x);
    const rootList = roots(coefficients);
    const expression = result.terms.map(monomial).join(" ŌŖĢ ");

    polyOutput.innerHTML = `
      <p><strong>f(x)</strong> = ${expression}</p>
      <p>f(${formatNumber(x)}) = min(${result.terms.map((term) => `${formatNumber(term.coefficient)} + ${term.degree}┬Ę${formatNumber(x)} = ${formatNumber(term.value)}`).join(", ")}) = <strong>${formatNumber(result.value)}</strong></p>
      <p class="tropical-muted">winning term${result.winners.length === 1 ? "" : "s"}: ${result.winners.map(monomial).join(", ")}</p>
    `;

    rootsOutput.innerHTML = rootList.length
      ? `<p><strong>tropical roots</strong> occur where at least two terms tie for the minimum:</p><ul>${rootList.map((root) => `<li>x = <strong>${formatNumber(root.x)}</strong> from degrees ${root.terms.join(", ")}</li>`).join("")}</ul>`
      : `<p class="tropical-muted">No tropical roots: a single term wins everywhere in the visible lower envelope.</p>`;

    renderPlot(coefficients, readNumber(xMinInput, "x min"), readNumber(xMaxInput, "x max"));
  } catch (error) {
    polyOutput.innerHTML = `<p>${escapeHtml(error instanceof Error ? error.message : String(error))}</p>`;
  }
}

function svg(tag: string, attrs: Record<string, string | number>, children = ""): string {
  const attrText = Object.entries(attrs).map(([key, value]) => `${key}="${escapeHtml(String(value))}"`).join(" ");
  return `<${tag} ${attrText}>${children}</${tag}>`;
}

function renderPlot(coefficients: number[], xMin: number, xMax: number) {
  if (!plot) return;
  if (xMax <= xMin) throw new Error("x max must be greater than x min");

  const width = 900;
  const height = 420;
  const pad = 46;
  const samples = Array.from({ length: 241 }, (_unused, i) => xMin + (i / 240) * (xMax - xMin));
  const values = samples.map((x) => evaluate(coefficients, x).value);
  const yMin = Math.min(...values);
  const yMax = Math.max(...values);
  const ySpan = yMax - yMin || 1;
  const xToSvg = (x: number) => pad + ((x - xMin) / (xMax - xMin)) * (width - 2 * pad);
  const yToSvg = (y: number) => height - pad - ((y - yMin) / ySpan) * (height - 2 * pad);
  const path = samples.map((x, i) => `${i === 0 ? "M" : "L"}${xToSvg(x).toFixed(2)},${yToSvg(values[i]).toFixed(2)}`).join(" ");
  const rootMarks = roots(coefficients)
    .filter((root) => root.x >= xMin && root.x <= xMax)
    .map((root) => svg("g", {}, `${svg("circle", { cx: xToSvg(root.x), cy: yToSvg(evaluate(coefficients, root.x).value), r: 5, fill: "currentColor" })}${svg("text", { x: xToSvg(root.x) + 8, y: yToSvg(evaluate(coefficients, root.x).value) - 8, "font-size": 12, fill: "currentColor" }, `x=${formatNumber(root.x)}`)}`))
    .join("");
  const termLines = coefficients.map((coefficient, degree) => ({ coefficient, degree })).filter((term) => Number.isFinite(term.coefficient)).map((term) => {
    const y1 = term.coefficient + term.degree * xMin;
    const y2 = term.coefficient + term.degree * xMax;
    return svg("line", { x1: xToSvg(xMin), y1: yToSvg(y1), x2: xToSvg(xMax), y2: yToSvg(y2), stroke: "currentColor", "stroke-opacity": 0.18, "stroke-width": 1 });
  }).join("");

  plot.setAttribute("viewBox", `0 0 ${width} ${height}`);
  plot.innerHTML = `
    ${svg("line", { x1: pad, y1: height - pad, x2: width - pad, y2: height - pad, stroke: "currentColor", "stroke-opacity": 0.35 })}
    ${svg("line", { x1: pad, y1: pad, x2: pad, y2: height - pad, stroke: "currentColor", "stroke-opacity": 0.35 })}
    ${termLines}
    ${svg("path", { d: path, fill: "none", stroke: "currentColor", "stroke-width": 3, "stroke-linejoin": "round" })}
    ${rootMarks}
    ${svg("text", { x: pad, y: height - 14, "font-size": 12, fill: "currentColor" }, `x ${formatNumber(xMin)} ŌĆ” ${formatNumber(xMax)}`)}
    ${svg("text", { x: pad, y: 20, "font-size": 12, fill: "currentColor" }, `f(x) ${formatNumber(yMin)} ŌĆ” ${formatNumber(yMax)}`)}
  `;
}

arithmeticForm?.addEventListener("submit", (event) => {
  event.preventDefault();
  renderArithmetic();
});

polyForm?.addEventListener("submit", (event) => {
  event.preventDefault();
  renderPolynomial();
});

[aInput, bInput].forEach((input) => input?.addEventListener("input", renderArithmetic));
[coefficientsInput, xInput, xMinInput, xMaxInput].forEach((input) => input?.addEventListener("input", renderPolynomial));

renderArithmetic();
renderPolynomial();

---
import BaseLayout from './BaseLayout.astro';

interface Props {
  name: string;
  back?: boolean;
  wide?: boolean;
}

const { name, back = false, wide = false } = Astro.props;
const title = name === 'incomplete.fun' ? name : `${name} - incomplete.fun`;
---

<BaseLayout title={title}>
  <div class="app-shell">
    <div class="topbar">
      {back && <a class="back-link" href="/" aria-label="Back to home">ŌåÉ</a>}
      <span><strong>{name}</strong></span>
    </div>
    <main class={wide ? 'page page-wide' : 'page'}>
      <slot />
    </main>
  </div>
</BaseLayout>

:root {
  color-scheme: light dark;
  --bg: #fbfbf9;
  --fg: #181817;
  --muted: #77736b;
  --line: #dedbd2;
  --accent: currentColor;
  --border: var(--line);
  --mono: inherit;
  --space: clamp(1rem, 4vw, 2.5rem);
  --measure: 38rem;
  font-family: ui-monospace, "SFMono-Regular", Menlo, Consolas, monospace;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #10100f;
    --fg: #eeeeea;
    --muted: #98948b;
    --line: #2d2b28;
  }
}

* { box-sizing: border-box; }

body {
  margin: 0;
  background: var(--bg);
  color: var(--fg);
  font-size: 15px;
  line-height: 1.65;
}

a {
  color: inherit;
  text-decoration: underline;
  text-decoration-color: var(--line);
  text-underline-offset: .25em;
}

a:hover { text-decoration-color: currentColor; }

h1, h2, h3, p, ul, ol { margin: 0 0 1rem; }

h1, h2, h3, strong { font-weight: 600; }

ul, ol { padding-left: 1.25rem; }

code {
  padding: .1em .3em;
  border: 1px solid var(--line);
  border-radius: 3px;
}

.app-shell, .canvas-app {
  min-height: 100dvh;
  background: var(--bg);
}

.app-shell { display: grid; grid-template-rows: auto 1fr; }
.canvas-app { display: flex; flex-direction: column; }

.topbar {
  display: flex;
  align-items: center;
  gap: 1rem;
  min-height: 3.25rem;
  padding: .75rem var(--space);
  border-bottom: 1px solid var(--line);
  flex-wrap: wrap;
}

.back-link {
  color: var(--muted);
  text-decoration: none;
}

.page {
  width: min(100%, var(--measure));
  margin: 0 auto;
  padding: calc(var(--space) * 1.4) var(--space);
}

.page-wide { --measure: 72rem; }

.home-intro { color: var(--muted); }

.home-links {
  list-style: none;
  padding: 0;
}

.home-links a {
  display: inline-block;
  padding: .15rem 0;
}

.canvas-stage {
  position: relative;
  flex: 1;
  overflow: hidden;
}

button, input {
  font: inherit;
  color: inherit;
}

.toolbar-button,
.metric-button {
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 999px;
  padding: .15rem .7rem;
  cursor: pointer;
}

.toolbar-button:hover,
.metric-button:hover,
.metric-button.is-active {
  background: var(--fg);
  border-color: var(--fg);
  color: var(--bg);
}

.control-label {
  display: inline-flex;
  align-items: center;
  gap: .4rem;
  color: var(--muted);
}

input[type="number"] {
  width: 3.5rem;
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 4px;
  padding: .1rem .35rem;
}

input[type="color"] {
  width: 2rem;
  height: 1.4rem;
  padding: 0;
  border: 1px solid var(--line);
  background: transparent;
}

input[type="checkbox"],
input[type="range"] {
  accent-color: var(--fg);
}

---
import BaseLayout from '../layouts/BaseLayout.astro';
---

<BaseLayout title="voronoi - incomplete.fun">
  <div class="canvas-app" id="voronoi-app">
    <div class="topbar" id="voronoi-toolbar">
      <a class="back-link" href="/" aria-label="Back to home">ŌåÉ</a>
      <span><strong>voronoi</strong></span>
      <span style="color: var(--border);">|</span>

      <button class="metric-button" type="button" data-metric="minkowski05" title="minkowski p=1/2 (star)">L┬Į</button>
      <button class="metric-button" type="button" data-metric="manhattan" title="manhattan (diamond)">L1</button>
      <button class="metric-button" type="button" data-metric="euclidean" title="euclidean (circular)">L2</button>
      <button class="metric-button" type="button" data-metric="minkowski3" title="minkowski p=3 (rounded square)">L3</button>
      <button class="metric-button" type="button" data-metric="chebyshev" title="chebyshev (square)">LŌł×</button>

      <span id="voronoi-help" style="color: var(--muted); font-size: 0.75rem; margin-left: auto;">
        click to place ┬Ę right-click removes
      </span>
      <button class="toolbar-button" id="voronoi-clear" type="button">clear</button>
    </div>

    <div id="voronoi-hover-row">
      <span id="voronoi-coords">(0, 0)</span>
      <div id="voronoi-distances"></div>
    </div>

    <div class="canvas-stage" id="voronoi-stage" style="cursor: crosshair; touch-action: none;">
      <canvas id="voronoi-gl" style="position: absolute; inset: 0; display: block;"></canvas>
      <canvas id="voronoi-markers" style="position: absolute; inset: 0; display: block; pointer-events: none;"></canvas>
      <div id="voronoi-webgl-error" role="status">
        WebGL2 is required for this experiment.
      </div>
      <div id="voronoi-empty">
        <span>click to place points</span>
        <span style="font-size: 0.75rem;">each point uses its own distance metric</span>
      </div>
    </div>
  </div>
</BaseLayout>

<style>
  .metric-button {
    background: none;
    border: 1px solid var(--border);
    color: var(--fg);
    font-family: var(--mono);
    font-size: 0.8rem;
    padding: 0.15rem 0.55rem;
    cursor: pointer;
    border-radius: 2px;
  }

  .metric-button.is-active {
    background: var(--accent);
    border-color: var(--accent);
    color: #fff;
  }

  #voronoi-hover-row {
    display: grid;
    grid-template-columns: 6.5rem minmax(0, 1fr);
    column-gap: 0.75rem;
    padding: 0 1rem;
    border-bottom: 1px solid var(--border);
    font-size: 0.78rem;
    font-family: var(--mono);
    line-height: 1.25;
    min-height: 1.9rem;
    max-height: 6.5rem;
    overflow-x: hidden;
    overflow-y: auto;
    font-variant-numeric: tabular-nums;
  }

  #voronoi-coords {
    color: var(--muted);
    white-space: nowrap;
    padding-top: 0.35rem;
    visibility: hidden;
  }

  #voronoi-distances {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(18rem, 1fr));
    gap: 0.25rem 0.75rem;
    min-width: 0;
    padding: 0.25rem 0;
  }

  #voronoi-webgl-error,
  #voronoi-empty {
    position: absolute;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    gap: 0.4rem;
    color: var(--muted);
    font-family: var(--mono);
    pointer-events: none;
  }

  #voronoi-webgl-error {
    display: none;
  }
</style>

<style is:global>
  /* Applied to elements created dynamically in voronoi.ts */
  .distance-entry {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    min-width: 0;
    color: var(--muted);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .distance-entry.is-winner {
    color: var(--fg);
    font-weight: bold;
  }

  .distance-dot {
    display: inline-block;
    width: 7px;
    height: 7px;
    border-radius: 50%;
    flex-shrink: 0;
  }

  .distance-label {
    color: var(--muted);
    font-size: 0.72rem;
    flex-shrink: 0;
  }

  .distance-value {
    overflow: hidden;
    text-overflow: ellipsis;
  }
</style>

<script>
  import '../scripts/voronoi.ts';
