    ca2Canvas.setPointerCapture(event.pointerId);
    const point = canvasPoint(ca2Canvas, event);
    const x = clamp(Math.floor(point.x / cell), 0, cols - 1);
    const y = clamp(Math.floor(point.y / cell), 0, rows - 1);
